request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?intermediate ?intermediateName ?intermediateType WHERE {
  ?startTask bbo:name ?startName .
  ?endTask bbo:name ?endName .
  FILTER(CONTAINS(?startName, "Musterrohstoff"))
  FILTER(CONTAINS(?endName, "Produktstart"))

  ?flow1 a bbo:SequenceFlow ;
         bbo:has_sourceRef ?startTask ;
         bbo:has_targetRef ?intermediate .
  ?flow2 a bbo:SequenceFlow ;
         bbo:has_sourceRef ?intermediate ;
         bbo:has_targetRef ?endTask .

  ?intermediate a ?intermediateType ;
                bbo:name ?intermediateName .
}
LIMIT 25
